 5→interface ProjectEntry {
 6→	organizationId: string;
 7→}
 8→
 9→interface ProjectsConfig {
10→	projects: Record<string, ProjectEntry>;
11→}
12→
13→function getConfigDir(): string {
14→	return (
15→		process.env.RUDEL_CONFIG_DIR ?? join(process.env.HOME ?? "~", ".rudel")
16→	);
17→}
18→
19→function getProjectsConfigPath(): string {
20→	return join(getConfigDir(), "projects.json");
21→}
22→
23→function loadProjectsConfig(): ProjectsConfig {
24→	const path = getProjectsConfigPath();
25→	if (!existsSync(path)) return { projects: {} };
26→	const content = readFileSync(path, "utf-8");
27→	return JSON.parse(content) as ProjectsConfig;
28→}
