69→export async function getProjectOrgId(
70→	cwd: string,
71→): Promise<string | undefined> {
72→	const key = await getProjectKey(cwd);
73→	const config = loadProjectsConfig();
74→	return config.projects[key]?.organizationId;
75→}
76→
77→export async function setProjectOrgId(
78→	cwd: string,
79→	organizationId: string,
80→): Promise<void> {
81→	const key = await getProjectKey(cwd);
82→	const config = loadProjectsConfig();
83→	config.projects[key] = { organizationId };
84→	saveProjectsConfig(config);
85→}
