 1→import { createInterface } from "node:readline";
 2→import { buildCommand } from "@stricli/core";
 3→import { createApiClient } from "../lib/api-client.js";
 4→import { loadCredentials } from "../lib/credentials.js";
 5→import { getProjectOrgId, setProjectOrgId } from "../lib/project-config.js";
 6→
 7→async function promptChoice(question: string, max: number): Promise<number> {
 8→	const rl = createInterface({ input: process.stdin, output: process.stdout });
 9→	return new Promise((resolve) => {
10→		rl.question(question, (answer) => {
11→			rl.close();
12→			const num = Number.parseInt(answer.trim(), 10);
13→			if (Number.isNaN(num) || num < 1 || num > max) {
14→				resolve(1);
15→			} else {
16→				resolve(num);
17→			}
18→		});
19→	});
20→}
21→
22→async function runSetOrg(): Promise<void> {
23→	const write = (msg: string) => process.stdout.write(`${msg}\n`);
24→	const writeError = (msg: string) => process.stderr.write(`${msg}\n`);
25→
26→	const credentials = loadCredentials();
27→	if (!credentials) {
28→		writeError("Error: Not authenticated. Run `rudel login` first.");
29→		process.exitCode = 1;
30→		return;
31→	}
32→
33→	const client = createApiClient(credentials);
34→	let orgs: { id: string; name: string; slug: string }[];
35→	try {
36→		orgs = await client.listMyOrganizations();
37→	} catch {
38→		writeError("Error: Failed to fetch organizations. Check your connection.");
39→		process.exitCode = 1;
40→		return;
41→	}
42→
43→	if (orgs.length === 0) {
44→		writeError(
45→			"Error: No organizations found. Create one at app.rudel.ai first.",
46→		);
47→		process.exitCode = 1;
48→		return;
49→	}
50→
51→	const cwd = process.cwd();
52→	const currentOrgId = await getProjectOrgId(cwd);
53→	const currentOrg = currentOrgId
54→		? orgs.find((o) => o.id === currentOrgId)
55→		: undefined;
56→
57→	if (currentOrg) {
58→		write(`Current organization: ${currentOrg.name} (${currentOrg.slug})`);
59→	}
60→
61→	write("Select an organization for this repository:");
62→	for (const [i, org] of orgs.entries()) {
63→		const marker = org.id === currentOrgId ? " (current)" : "";
64→		write(`  ${i + 1}. ${org.name} (${org.slug})${marker}`);
65→	}
66→
67→	const choice = await promptChoice(`Choice [1-${orgs.length}]: `, orgs.length);
68→	const selected = orgs[choice - 1] ?? orgs[0];
69→	if (!selected) return;
70→	await setProjectOrgId(cwd, selected.id);
71→	write(`Organization set to: ${selected.name}`);
72→}
73→
74→export const setOrgCommand = buildCommand({
75→	loader: async () => ({ default: runSetOrg }),
76→	parameters: {},
77→	docs: {
78→		brief: "Set the organization for the current repository",
79→	},
80→});
