---

### Pattern 4: API Mocking / Real Server Spawning

Tests do NOT mock API calls or use mock RPC clients. Instead, they spawn a real API server process on a random port and make real HTTP requests against it.

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:18-63`

The `startTestServer()` function spawns the actual API server with `PORT=0`:

```typescript
export async function startTestServer(): Promise<TestServer> {
	const env = {
		...process.env,
		PORT: "0",
		APP_URL: "http://localhost",
		BETTER_AUTH_SECRET: "test-secret-for-integration-tests",
		ALLOWED_ORIGIN: "http://localhost",
	};

	let proc = spawnServer(env);
	let port = await parseReadyPort(proc);
	drainStreams(proc);
	await waitForReady(`http://localhost:${port}`);

	const server: TestServer = {
		get port() { return port; },
		get baseUrl() { return `http://localhost:${port}`; },
		get rpcUrl() { return `http://localhost:${port}/rpc`; },
		async stop() {
			proc.kill();
			await proc.exited;
		},
		async ensureAlive() {
			try {
				const res = await fetch(`http://localhost:${port}/health`, {
					signal: AbortSignal.timeout(2000),
				});
				if (res.ok) return;
			} catch {
				// Server is dead -- restart it
			}
			proc = spawnServer(env);
			port = await parseReadyPort(proc);
			drainStreams(proc);
			await waitForReady(`http://localhost:${port}`);
		},
	};

	return server;
}
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:65-83`

The server is spawned as a child process using `Bun.spawn` with `proc.unref()` so it does not block test exit:

```typescript
function spawnServer(env: Record<string, string | undefined>) {
	const proc = Bun.spawn(["bun", "apps/api/src/index.ts"], {
		cwd: MONOREPO_ROOT,
		stdout: "pipe",
		stderr: "pipe",
		env,
	});
	proc.unref();
	return proc;
}

function drainStreams(proc: ReturnType<typeof Bun.spawn>) {
	if (proc.stdout instanceof ReadableStream) {
		proc.stdout.pipeTo(new WritableStream()).catch(() => {});
	}
	if (proc.stderr instanceof ReadableStream) {
		proc.stderr.pipeTo(new WritableStream()).catch(() => {});
	}
}
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:89-129`

Port detection reads stdout line-by-line looking for the "listening on" message:

```typescript
async function parseReadyPort(
	proc: ReturnType<typeof Bun.spawn>,
): Promise<number> {
	const stdout = proc.stdout;
	if (!stdout || !(stdout instanceof ReadableStream)) {
		throw new Error("Server process has no readable stdout");
	}

	const reader = stdout.getReader();
	const decoder = new TextDecoder();
	let buffer = "";
	const deadline = Date.now() + 30_000;

	try {
		while (Date.now() < deadline) {
			const { value, done } = await reader.read();
			if (done) break;
			buffer += decoder.decode(value, { stream: true });

			const match = buffer.match(/listening on https?:\/\/localhost:(\d+)/i);
			if (match?.[1]) {
				reader.releaseLock();
				return Number.parseInt(match[1], 10);
			}
		}
	} catch {
		// reader error
	}

	let stderrText = "";
	if (proc.stderr instanceof ReadableStream) {
		stderrText = await new Response(proc.stderr).text();
	}

	proc.kill();
	throw new Error(
		`Server did not become ready within 30 s.\nstdout buffer: ${buffer}\nstderr: ${stderrText}`,
	);
}
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/api-upload.integration.test.ts:39-43`

The `api-upload` test uses `beforeEach` to ensure the server is still alive (Bun's test runner can kill child processes between tests):

```typescript
beforeEach(async () => {
	await server.ensureAlive();
});
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/api-upload.integration.test.ts:59-76`

Tests that interact with ClickHouse use a retry pattern:

```typescript
let result = { success: false, error: "not attempted" } as Awaited<
	ReturnType<typeof uploadSession>
>;
for (let attempt = 0; attempt < 3; attempt++) {
	result = await uploadSession(request, {
		endpoint: server.rpcUrl,
		token: bearerToken,
	});
	if (result.success) break;
	await Bun.sleep(1000);
}

if (!result.success) {
	throw new Error(`uploadSession failed after 3 attempts: ${result.error}`);
}
expect(result.status).toBe(200);
```

---

### Pattern 5: Credentials and Auth in Tests

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:156-186`

User creation via the real `better-auth` sign-up endpoint. Returns a bearer token:

```typescript
export async function signUpTestUser(baseUrl: string): Promise<string> {
	const res = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
		method: "POST",
		headers: { "Content-Type": "application/json" },
		body: JSON.stringify({
			email: `test-${Date.now()}@example.com`,
			password: "test-password-123",
			name: "Test User",
		}),
	});

	if (!res.ok) {
		const body = await res.text();
		throw new Error(`Sign-up failed (${res.status}): ${body}`);
	}

	const data = (await res.json()) as { token?: string };

	if (data.token) return data.token;

	// Fallback: extract session token from set-cookie header
	const cookies = res.headers.getSetCookie();
	const sessionCookie = cookies
		.find((c) => c.startsWith("better-auth.session_token="))
		?.split("=")[1]
		?.split(";")[0];

	if (sessionCookie) return sessionCookie;

	throw new Error("Could not extract token from sign-up response");
}
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/api-upload.integration.test.ts:82-92`

For subprocess tests, credentials are injected by writing a `credentials.json` file and setting the `RUDEL_CONFIG_DIR` env var:

```typescript
// Write credentials file using the current server URL
const credDir = join(tempDir, "cli-creds");
await mkdir(credDir, { recursive: true });
await writeFile(
	join(credDir, "credentials.json"),
	JSON.stringify({ token: bearerToken, apiBaseUrl: server.baseUrl }),
);
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/lib/credentials.ts:16-17`

The `RUDEL_CONFIG_DIR` env var is the mechanism that makes this work -- the real `credentials.ts` module checks it:

```typescript
function getConfigDir(): string {
	return process.env.RUDEL_CONFIG_DIR ?? join(homedir(), ".rudel");
}
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/auth.e2e.test.ts:178-213`

The auth e2e test defines its own inline helper functions for managing credentials in the test config dir:

```typescript
function saveCredentialsToDir(
	dir: string,
	token: string,
	apiBaseUrl: string,
): void {
	const { writeFileSync } = require("node:fs");
	writeFileSync(
		join(dir, "credentials.json"),
		JSON.stringify({ token, apiBaseUrl }, null, 2),
		{ mode: 0o600 },
	);
}

function loadCredentialsFromDir(
	dir: string,
): { token: string; apiBaseUrl: string } | null {
	const path = join(dir, "credentials.json");
	try {
		const { readFileSync } = require("node:fs");
		const content = readFileSync(path, "utf-8");
		return JSON.parse(content);
	} catch {
		return null;
	}
}

function clearCredentialsFromDir(dir: string): void {
	const path = join(dir, "credentials.json");
	try {
		const { rmSync } = require("node:fs");
		rmSync(path);
	} catch {
		// already gone
	}
}
```

---

### Pattern 6: CLI Subprocess Testing

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/upload.integration.test.ts:307-336`

Dry-run tests invoke the CLI as a subprocess using `Bun.spawn`, capturing stdout/stderr:

```typescript
test("full CLI dry-run with file path and subagent files", async () => {
	const projectDir = join(tempDir, "cli-path-test2");
	await mkdir(projectDir, { recursive: true });

	const sessionFile = join(projectDir, "cli-test-session.jsonl");
