### Pattern 4: API Mocking / Real Server Spawning

Tests do NOT mock API calls or use mock RPC clients. Instead, they spawn a real API server process on a random port and make real HTTP requests against it.

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:18-63`

The `startTestServer()` function spawns the actual API server with `PORT=0`:

```typescript
export async function startTestServer(): Promise<TestServer> {
	const env = {
		...process.env,
		PORT: "0",
		APP_URL: "http://localhost",
		BETTER_AUTH_SECRET: "test-secret-for-integration-tests",
		ALLOWED_ORIGIN: "http://localhost",
	};

	let proc = spawnServer(env);
	let port = await parseReadyPort(proc);
	drainStreams(proc);
	await waitForReady(`http://localhost:${port}`);

	const server: TestServer = {
		get port() { return port; },
		get baseUrl() { return `http://localhost:${port}`; },
		get rpcUrl() { return `http://localhost:${port}/rpc`; },
		async stop() {
			proc.kill();
			await proc.exited;
		},
		async ensureAlive() {
			try {
				const res = await fetch(`http://localhost:${port}/health`, {
					signal: AbortSignal.timeout(2000),
				});
				if (res.ok) return;
			} catch {
				// Server is dead -- restart it
			}
			proc = spawnServer(env);
			port = await parseReadyPort(proc);
			drainStreams(proc);
			await waitForReady(`http://localhost:${port}`);
		},
	};

	return server;
}
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:65-83`

The server is spawned as a child process using `Bun.spawn` with `proc.unref()` so it does not block test exit:

```typescript
function spawnServer(env: Record<string, string | undefined>) {
	const proc = Bun.spawn(["bun", "apps/api/src/index.ts"], {
		cwd: MONOREPO_ROOT,
		stdout: "pipe",
		stderr: "pipe",
		env,
	});
	proc.unref();
	return proc;
}

function drainStreams(proc: ReturnType<typeof Bun.spawn>) {
	if (proc.stdout instanceof ReadableStream) {
		proc.stdout.pipeTo(new WritableStream()).catch(() => {});
	}
	if (proc.stderr instanceof ReadableStream) {
		proc.stderr.pipeTo(new WritableStream()).catch(() => {});
	}
}
```

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:89-129`

Port detection reads stdout line-by-line looking for the "listening on" message:

```typescript
async function parseReadyPort(
	proc: ReturnType<typeof Bun.spawn>,
): Promise<number> {
	const stdout = proc.stdout;
	if (!stdout || !(stdout instanceof ReadableStream)) {
		throw new Error("Server process has no readable stdout");
	}

	const reader = stdout.getReader();
	const decoder = new TextDecoder();
	let buffer = "";
	const deadline = Date.now() + 30_000;

	try {
		while (Date.now() < deadline) {
			const { value, done } = await reader.read();
			if (done) break;
			buffer += decoder.decode(value, { stream: true });

			const match = buffer.match(/listening on https?:\/\/localhost:(\d+)/i);
			if (match?.[1]) {
				reader.releaseLock();
				return Number.parseInt(match[1], 10);
			}
		}
	} catch {
		// reader error
	}

	let stderrText = "";
	if (proc.stderr instanceof ReadableStream) {
		stderrText = await new Response(proc.stderr).text();
	}

	proc.kill();
	throw new Error(
		`Server did not become ready within 30 s.\nstdout buffer: ${buffer}\nstderr: ${stderrText}`,
	);
}
```

