### Pattern 5: Credentials and Auth in Tests

**Found in**: `/Users/marc/conductor/workspaces/rudel/chennai/apps/cli/src/__tests__/helpers/bun-server.ts:156-186`

User creation via the real `better-auth` sign-up endpoint. Returns a bearer token:

```typescript
export async function signUpTestUser(baseUrl: string): Promise<string> {
	const res = await fetch(`${baseUrl}/api/auth/sign-up/email`, {
		method: "POST",
		headers: { "Content-Type": "application/json" },
		body: JSON.stringify({
			email: `test-${Date.now()}@example.com`,
			password: "test-password-123",
			name: "Test User",
		}),
	});

	if (!res.ok) {
		const body = await res.text();
		throw new Error(`Sign-up failed (${res.status}): ${body}`);
	}

	const data = (await res.json()) as { token?: string };

	if (data.token) return data.token;

	// Fallback: extract session token from set-cookie header
	const cookies = res.headers.getSetCookie();
	const sessionCookie = cookies
		.find((c) => c.startsWith("better-auth.session_token="))
		?.split("=")[1]
		?.split(";")[0];

	if (sessionCookie) return sessionCookie;

	throw new Error("Could not extract token from sign-up response");
}
```

