24→export function saveCredentials(token: string, apiBaseUrl: string): void {
25→	const dir = getConfigDir();
26→	if (!existsSync(dir)) {
27→		mkdirSync(dir, { recursive: true, mode: 0o700 });
28→	}
29→	const data: Credentials = { token, apiBaseUrl };
30→	writeFileSync(getCredentialsPath(), JSON.stringify(data, null, 2), {
31→		mode: 0o600,
32→	});
33→}
34→
35→export function loadCredentials(): Credentials | null {
36→	const path = getCredentialsPath();
37→	if (!existsSync(path)) return null;
38→	const content = readFileSync(path, "utf-8");
39→	return JSON.parse(content) as Credentials;
40→}
41→
42→export function clearCredentials(): void {
43→	const path = getCredentialsPath();
44→	if (existsSync(path)) {
