# OK so the decode is correct — it IS a nested path. Good.
# Now let's verify our ENCODE function works correctly for findProjectSessions.
# The key question: when `rudel enable` runs in cwd, what does cwd look like?

# Test our encode matches Claude Code's encoding
bun -e '
function encodeProjectPath(projectPath) {
  return projectPath.replace(/\//g, "-");
}

const tests = [
  "/Users/marc/Workspace/rudel",
  "/Users/marc/Workspace/claude-marketplace",
  "/Users/marc/Workspace/flick-2",
  "/Users/marc/conductor/workspaces/rudel/chennai",
];

for (const path of tests) {
  const encoded = encodeProjectPath(path);
  console.log(`encode("${path}") → "${encoded}"`);
}
'

# Perfect - all match exactly. Now let's do the full end-to-end test:
# Does findProjectSessions work with the REAL cwd and REAL sessions?
bun -e '
import { ClaudeCodeAgent } from "./apps/cli/src/lib/agents/claude-code.ts";

const agent = new ClaudeCodeAgent();
const cwd = process.cwd(); // /Users/marc/conductor/workspaces/rudel/chennai

console.log("cwd:", cwd);
const sessions = await agent.findProjectSessions(cwd);
console.log(`Found ${sessions.length} sessions for ${cwd}`);
for (const s of sessions.slice(0, 5)) {
  console.log(`  ${s.sessionId}`);
}
if (sessions.length > 5) console.log(`  ... and ${sessions.length - 5} more`);

// Also test with the main rudel workspace
const rudel = "/Users/marc/Workspace/rudel";
const rudelSessions = await agent.findProjectSessions(rudel);
console.log(`\nFound ${rudelSessions.length} sessions for ${rudel}`);
for (const s of rudelSessions.slice(0, 5)) {
  console.log(`  ${s.sessionId}`);
}
if (rudelSessions.length > 5) console.log(`  ... and ${rudelSessions.length - 5} more`);
'
